import React, { useState, useContext } from "react";
import { useNavigate } from "react-router-dom";
import { StoreContext } from "../../context/StoreContext";
import axios from "axios";

function LoginPopup({ setShowLogin }) {
    const { url, setToken } = useContext(StoreContext);
    const navigate = useNavigate();
    const [currState, setCurrState] = useState("Login");
    const [data, setData] = useState({ name: "", email: "", password: "" });

    const onLogin = async (e) => {
        e.preventDefault();
        
        try {
            const response = await axios.post(
                `${url}/api/user/${currState === "Login" ? "login" : "register"}`,
                data
            );

            if (response.data.success) {
                if (response.data.token) {
                    setToken(response.data.token);
                    localStorage.setItem("token", response.data.token);
                    setShowLogin(false);
                } else if (response.data.requiresOTP) {
                    // Navigate to OTP verification page
                    setShowLogin(false);
                    navigate('/verify-otp', { state: { email: response.data.email } });
                }
            }
        } catch (error) {
            const errorData = error.response?.data;
            
            if (errorData?.requiresOTP) {
                // Navigate to OTP page
                setShowLogin(false);
                navigate('/verify-otp', { state: { email: errorData.email } });
            } else {
                alert(errorData?.message || "Error");
            }
        }
    };

    return (
        <div className="login-popup">
            <form onSubmit={onLogin}>
                {/* Your existing form JSX */}
            </form>
        </div>
    );
}

export default LoginPopup;
